import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import '../../estilos/admin.css';
import { 
  listarUsuariosAPI, 
  eliminarUsuarioAPI, 
  obtenerProductosAPI, 
  obtenerPaquetesAPI,
  obtenerTodasLasSolicitudesAPI,
  getUsuarioLocal,
  cerrarSesion
} from '../../servicios/api';

const PaginaAdmin = () => {
  const navigate = useNavigate();
  const [vistaActiva, setVistaActiva] = useState('usuarios');
  const [pestanaSolicitudes, setPestanaSolicitudes] = useState('paquetes'); // paquetes | pedidos | personalizado

  const [usuarios, setUsuarios] = useState([]);
  const [productos, setProductos] = useState([]);
  const [paquetes, setPaquetes] = useState([]);
  const [solicitudesPaquetes, setSolicitudesPaquetes] = useState([]);
  const [solicitudesPedidos, setSolicitudesPedidos] = useState([]);
  const [solicitudesPersonal, setSolicitudesPersonal] = useState([]);

  const [cargando, setCargando] = useState(false);
  const [userLocal] = useState(getUsuarioLocal());

  // Seguridad: Verificar rol admin
  useEffect(() => {
    if (!userLocal || (userLocal.rol !== 'admin' && userLocal.rol !== 'administrador')) {
      navigate('/login');
    }
  }, [userLocal, navigate]);

  // Cargar datos según la vista
  useEffect(() => {
    cargarDatos();
  }, [vistaActiva, pestanaSolicitudes]);

  const cargarDatos = async () => {
    setCargando(true);
    try {
      if (vistaActiva === 'usuarios') {
        const res = await listarUsuariosAPI();
        setUsuarios(res);
      } else if (vistaActiva === 'productos') {
        const res = await obtenerProductosAPI();
        setProductos(res);
      } else if (vistaActiva === 'paquetes') {
        const res = await obtenerPaquetesAPI();
        setPaquetes(res);
      } else if (vistaActiva === 'solicitudes') {
        if (pestanaSolicitudes === 'paquetes') {
           const res = await obtenerTodasLasSolicitudesAPI('paquetes'); // Nota: Asumimos que el backend maneja esto o que necesitamos ajustar
           // Para el prototipo, intentamos traer lo que haya
           setSolicitudesPaquetes(Array.isArray(res) ? res : []);
        } else if (pestanaSolicitudes === 'pedidos') {
           const res = await obtenerTodasLasSolicitudesAPI('productos');
           setSolicitudesPedidos(Array.isArray(res) ? res : []);
        } else if (pestanaSolicitudes === 'personalizado') {
           const res = await obtenerTodasLasSolicitudesAPI('personalizado');
           setSolicitudesPersonal(Array.isArray(res) ? res : []);
        }
      }
    } catch (error) {
      console.error('Error cargando datos admin:', error);
    } finally {
      setCargando(false);
    }
  };

  const handleLogout = () => {
    cerrarSesion();
    navigate('/login');
  };

  const eliminarUsuario = async (id) => {
    if (window.confirm('¿Seguro que deseas eliminar este usuario?')) {
      try {
        await eliminarUsuarioAPI(id);
        setUsuarios(usuarios.filter(u => u.Id_Usuario !== id));
      } catch (error) {
        alert(error.message);
      }
    }
  };

  const formatearDinero = (monto) => {
     if (monto === undefined || monto === null) return '$0';
     return `$${Number(monto).toLocaleString('es-CO')}`;
  };

  return (
    <div className="pagina-admin-root">
      {/* ══ MENÚ LATERAL ══ */}
      <aside className="menu-lateral">
        <div className="menu-lateral__contenedor-logo">
          <div className="menu-lateral__texto-logo">Lion <span>Admin</span></div>
        </div>

        <nav className="menu-lateral__navegacion">
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'usuarios' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('usuarios')}
          >
            <i className="fas fa-users"></i> <span>Usuarios</span>
          </div>
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'paquetes' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('paquetes')}
          >
            <i className="fas fa-camera"></i> <span>Paquetes</span>
          </div>
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'productos' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('productos')}
          >
            <i className="fas fa-box-open"></i> <span>Productos</span>
          </div>
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'solicitudes' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('solicitudes')}
          >
            <i className="fas fa-envelope-open-text"></i> <span>Solicitudes</span>
            <span className="menu-lateral__contador-pendientes">!</span>
          </div>
        </nav>

        <div className="menu-lateral__pie" onClick={handleLogout} style={{cursor:'pointer'}}>
          <div className="menu-lateral__informacion-admin">
            <div className="menu-lateral__avatar-admin">{userLocal?.Nombre?.charAt(0) || 'A'}</div>
            <div>
              <div className="menu-lateral__nombre-admin" style={{fontSize:'0.8rem', fontWeight:600}}>{userLocal?.Nombre || 'Admin'}</div>
              <div className="menu-lateral__rol-admin" style={{fontSize:'0.65rem', color:'var(--rojo)'}}>Cerrar sesión</div>
            </div>
          </div>
        </div>
      </aside>

      {/* ══ ÁREA DE CONTENIDO ══ */}
      <main className="area-contenido">
        <header className="barra-encabezado">
          <div className="seccion-pagina__titulo">
            {vistaActiva === 'usuarios' && <>Gestión de <span>Usuarios</span></>}
            {vistaActiva === 'paquetes' && <>Gestión de <span>Paquetes</span></>}
            {vistaActiva === 'productos' && <>Gestión de <span>Productos</span></>}
            {vistaActiva === 'solicitudes' && <>Centro de <span>Solicitudes</span></>}
          </div>
          <div className="barra-encabezado__acciones">
            <span style={{color: 'var(--verde)'}}>●</span>
            <span style={{fontSize:'0.65rem', marginLeft:'5px', letterSpacing:'1px'}}>SISTEMA ACTIVO</span>
          </div>
        </header>

        <div className="contenedor-secciones">
          {cargando ? (
            <div className="loader" style={{textAlign:'center', marginTop:'4rem'}}>
               <i className="fas fa-circle-notch fa-spin" style={{fontSize:'2rem', color:'var(--rojo)'}}></i>
               <p style={{marginTop:'1rem', fontFamily:'Rajdhani'}}>Cargando datos maestros...</p>
            </div>
          ) : (
            <>
              {/* VISTA USUARIOS */}
              {vistaActiva === 'usuarios' && (
                <section className="seccion-pagina">
                  <div className="cuadricula-usuarios">
                    {usuarios.map(u => (
                      <div key={u.Id_Usuario} className="tarjeta-usuario">
                        <div className="tarjeta-usuario__encabezado">
                          <div className="tarjeta-usuario__avatar">{u.Nombre?.charAt(0)}</div>
                          <div className="tarjeta-usuario__identidad">
                            <div className="tarjeta-usuario__nombre-completo" style={{fontWeight:700}}>{u.Nombre} {u.Apellidos}</div>
                            <div className={`etiqueta-rol ${ (u.Rol?.Nombre_Rol === 'admin' || u.Rol?.Nombre_Rol === 'administrador') ? 'etiqueta-rol--administrador' : 'etiqueta-rol--cliente'}`}>
                               {u.Rol?.Nombre_Rol || 'cliente'}
                            </div>
                          </div>
                        </div>
                        <div style={{padding:'1.3rem'}}>
                          <div style={{fontSize:'0.75rem', color:'var(--texto-secundario)', marginBottom:'5px'}}>ID: #{String(u.Id_Usuario).padStart(4,'0')}</div>
                          <div style={{fontSize:'0.8rem', color:'var(--texto-primario)', marginBottom:'1rem'}}>{u.Correo}</div>
                          <div style={{display:'flex', gap:'8px'}}>
                            <button className="boton-accion boton-accion--eliminar" onClick={() => eliminarUsuario(u.Id_Usuario)}>
                              <i className="fas fa-trash"></i> Eliminar
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* VISTA PAQUETES */}
              {vistaActiva === 'paquetes' && (
                <section className="seccion-pagina">
                  <div className="grid-stats-admin">
                    <div className="stat-card-admin">
                       <div className="stat-value">{paquetes.length}</div>
                       <div className="stat-label">Paquetes registrados</div>
                    </div>
                  </div>
                  <div className="cuadricula-usuarios">
                    {paquetes.map(p => (
                      <div key={p.Id_Paquete} className="tarjeta-usuario">
                        <div style={{padding:'1.4rem'}}>
                          <div className="tarjeta-catalogo__nombre" style={{fontSize:'1.4rem', fontFamily:'Bebas Neue'}}>{p.Nombre_Paquete}</div>
                          <div style={{fontSize:'1.1rem', color:'var(--rojo)', fontFamily:'Rajdhani', fontWeight:700}}>{formatearDinero(p.Precio_Paquete)} COP</div>
                          <p style={{marginTop:'10px', fontSize:'0.75rem', color:'var(--texto-secundario)', minHeight:'40px'}}>{p.Descripcion_Paquete}</p>
                          <div style={{marginTop:'15px'}}>
                             <Link to={`/admin/editar-paquete/${p.Id_Paquete}`} className="boton-accion" style={{background:'rgba(255,255,255,0.05)', color:'#fff'}}>
                               <i className="fas fa-edit"></i> Editar
                             </Link>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* VISTA PRODUCTOS */}
              {vistaActiva === 'productos' && (
                <section className="seccion-pagina">
                  <div className="cuadricula-usuarios">
                    {productos.map(p => (
                      <div key={p.Id_Producto} className="tarjeta-usuario">
                        <div style={{padding:'1.4rem'}}>
                          <div className="tarjeta-catalogo__nombre" style={{fontSize:'1.4rem', fontFamily:'Bebas Neue'}}>{p.Nombre_Producto}</div>
                          <div className="stat-value" style={{fontSize:'1.3rem'}}>{formatearDinero(p.Precio_Producto)}</div>
                          <p style={{marginTop:'10px', fontSize:'0.75rem', color:'var(--texto-secundario)', minHeight:'40px'}}>{p.Descripcion_Producto}</p>
                          <div style={{marginTop:'15px', display:'flex', gap:'8px'}}>
                             <button className="boton-accion" style={{background:'rgba(255,255,255,0.05)', color:'#fff'}}>
                               <i className="fas fa-edit"></i> Editar
                             </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* VISTA SOLICITUDES */}
              {vistaActiva === 'solicitudes' && (
                <section className="seccion-pagina">
                  <div className="barra-pestanas">
                    <button 
                      className={`pestana-boton ${pestanaSolicitudes === 'paquetes' ? 'pestana-boton--activa' : ''}`}
                      onClick={() => setPestanaSolicitudes('paquetes')}
                    >
                      Citas (Paquetes)
                    </button>
                    <button 
                      className={`pestana-boton ${pestanaSolicitudes === 'pedidos' ? 'pestana-boton--activa' : ''}`}
                      onClick={() => setPestanaSolicitudes('pedidos')}
                    >
                      Pedidos (Productos)
                    </button>
                    <button 
                      className={`pestana-boton ${pestanaSolicitudes === 'personalizado' ? 'pestana-boton--activa' : ''}`}
                      onClick={() => setPestanaSolicitudes('personalizado')}
                    >
                      Personalizados
                    </button>
                  </div>

                  <div className="tabla-contenedor" style={{background:'var(--fondo-secundario)', borderRadius:'18px', border:'1px solid var(--borde-fuerte)', overflow:'hidden'}}>
                    <table className="tabla-solicitudes-premium">
                      <thead className="tabla-header">
                        <tr>
                          <th>ID</th>
                          <th>Cliente</th>
                          <th>Detalle</th>
                          <th>Fecha</th>
                          <th>Estado</th>
                        </tr>
                      </thead>
                      <tbody>
                        {pestanaSolicitudes === 'paquetes' && solicitudesPaquetes.map(s => (
                          <tr key={s.Id_Reserva_Paquete} className="tabla-row">
                            <td>#{s.Id_Reserva_Paquete}</td>
                            <td>{s.Nombre_Completo}</td>
                            <td>{s.Tipo_Evento}</td>
                            <td>{s.Fecha_Evento}</td>
                            <td>
                              <span className={`badge-estado ${s.Estado_Reserva_Paquete === 'pendiente' ? 'badge-pendiente' : 'badge-completada'}`}>
                                {s.Estado_Reserva_Paquete}
                              </span>
                            </td>
                          </tr>
                        ))}
                        {pestanaSolicitudes === 'pedidos' && solicitudesPedidos.map(s => (
                          <tr key={s.Id_Pedido} className="tabla-row">
                            <td>#{s.Id_Pedido}</td>
                            <td>{s.Nombre_Cliente || 'Usuario'}</td>
                            <td>Pedido de productos</td>
                            <td>{new Date(s.Fecha_Pedido).toLocaleDateString()}</td>
                            <td>
                              <span className={`badge-estado ${s.Estado === 'Pendiente' ? 'badge-pendiente' : 'badge-completada'}`}>
                                {s.Estado}
                              </span>
                            </td>
                          </tr>
                        ))}
                        {pestanaSolicitudes === 'personalizado' && solicitudesPersonal.map(s => (
                          <tr key={s.Id_Personalizado} className="tabla-row">
                            <td>#{s.Id_Personalizado}</td>
                            <td>{s.Nombre_Completo}</td>
                            <td>{s.Descripcion_Idea?.substring(0,30)}...</td>
                            <td>{s.Fecha_Solicitud}</td>
                            <td>
                              <span className={`badge-estado ${s.Estado_Personalizado === 'pendiente' ? 'badge-pendiente' : 'badge-completada'}`}>
                                {s.Estado_Personalizado}
                              </span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </section>
              )}
            </>
          )}
        </div>
      </main>
    </div>
  );
};

export default PaginaAdmin;
